script:
var waterBreathSkill = Skill.ManfishBoss_WaterBreath;

var nextCrabSpawn = 0.;
var crabPoints = [];
var activeCrabs = [];

function initCrabPoints() {
	clear(crabPoints);
	addCrabSpawn("CrabA");
	addCrabSpawn("CrabB");
	addCrabSpawn("CrabC");
	addCrabSpawn("CrabD");
	addCrabSpawn("CrabE");
	addCrabSpawn("CrabF");
	trace("Added " + crabPoints.length + " crab spawns");
}

function canBlockRotation() {
	return !isFree() && currentSequence != null;
}

function onEnterCombat() {
	initCrabPoints();
}

function onLeaveCombat() {
	clearCrabs();
}

function onCombatUpdate(dt) {
	updateCrabs(dt);
}

function onEnterSequence(seq) {
	switch(seq) {
		case Sequences.WaterBreath:
			moveTo("A");
		default:
	}
}

function onReachMoveTarget() {
	switch(currentSequence) {
		case Sequences.WaterBreath:
			lookTowards("B", 0.5);
			forceCast(waterBreathSkill);
		default:
	}
}

function onSkillEnd(skill, cancel) {
	switch(currentSequence) {
		case Sequences.WaterBreath:
			if(isSkill(skill, waterBreathSkill))
				leaveSequence();
		default:
	}
}



function addCrabSpawn(name) {
	var pt = getPoint(name);
	if(pt != null)
		crabPoints.push(pt);
}

function updateCrabs(dt) {
	filterOut(activeCrabs, c -> c.isDead());
	for(c in activeCrabs) {
		if(unit.targetUnit != null && c.target == null)
			c.aggroUnit(unit.targetUnit);
	}
}

function clearCrabs() {
	for(c in activeCrabs) {
		disbandFoe(c);
	}
	clear(activeCrabs);
}

var nayaSkill = Skill.R1CrabBoss_NayasFury;
var chargeSkill = Skill.R1CrabBoss_HuntDown;
var moveStatus: st.skill.Status;

function onCombatUpdate(dt) {
	switch(currentSequence) {
		case Sequences.NayasFury:
		default:
			if(isSkillReady(unit, nayaSkill)) {
				requestSequence(Sequences.NayasFury);
			}
	}
	/*if(isFree() && getCombatTimeSinceLastSkill() > vars.var2)
		forceCast(chargeSkill);*/
}

function onEnterSequence(seq) {
	switch(seq) {
		case Sequences.NayasFury:
			moveTo("A");
			moveStatus = addStatus(Skill.R1CrabBoss_NayasFuryMoveStatus);
		default:
			if(moveStatus != null)
				moveStatus.stop();
			moveStatus = null;
	}
}

function onReachMoveTarget() {
	switch(currentSequence) {
		case Sequences.NayasFury:
			if(moveStatus != null)
				moveStatus.stop();
			moveStatus = null;
			forceCast(nayaSkill);
		default:
	}
}

function onSkillEnd(skill, cancel) {
	switch(currentSequence) {
		case Sequences.NayasFury:
			if(isSkill(skill, nayaSkill)) {
				leaveSequence();
				updateAggro();
			}
		default:
	}
}

function onCombatEnd() {
	if(moveStatus != null)
		moveStatus.stop();
	moveStatus = null;
}

var fondueSkill = Skill.MChuck_SprayedFondue;
var healingSkill = Skill.MChuck_IsolatedHeal;
var fondueRunCount = 0;
var currentRoom = 0;

function onLeaveCombat() {
	leaveSequence();
	forceCancelSkill();
	currentRoom = 0;
}

function goToRoom(id: Int) {
	currentRoom = id;
	moveTo(getRoomName(id));
}

function getRoomName(id: Int) {
	return id == 0 ? "RoomA" : "RoomB";
}

var changeRoomMoveId = 0;
function onEnterSequence(seq) {
	switch(seq) {
		case Sequences.ChangeRoom:
			changeRoomMoveId = 0;
			var room = phase % 2;
			goToRoom(room);
		default:
	}
}

function onCombatUpdate(dt) {
	switch(currentSequence) {
		case Sequences.ChangeRoom:
			var sk = unit.getActiveSkill();
			if(isSkill(sk, healingSkill)) {
				var closest = getClosestHero();
				if(closest != null && isInRange(unit, closest, 40)) {
					leaveSequence();
					forceCancelSkill();
					foe.aggroUnit(closest);
				}
			}
		case Sequences.SprayedFondue:
		default:
			if(isSkillReady(unit, fondueSkill)) {
				requestSequence(Sequences.SprayedFondue);
				moveTo(currentRoom == 0 ? "A1" : "B1");
				fondueRunCount = 0;
			}
	}
}

function onReachMoveTarget() {
	switch(currentSequence) {
		case Sequences.SprayedFondue:
			forceCast(fondueSkill);
		case Sequences.ChangeRoom:
			if(changeRoomMoveId == 0) {
				var room = (phase - 1) % 2;
				goToRoom(room);
				changeRoomMoveId = 1;
			}
			else {
				forceCast(healingSkill);
			}
		default:
	}
}

function onSkillEnd(skill, cancel) {
	switch(currentSequence) {
		case Sequences.SprayedFondue:
			if(isSkill(skill, fondueSkill)) {
				fondueRunCount++;
				if(fondueRunCount < vars.var1 + phase-1) {
					wait(0.4, () -> forceCast(fondueSkill)); // Have to wait to avoid strange interaction with skill recasting
				}
				else {
					leaveSequence();
					updateAggro();
				}
			}
		default:
	}
}

function onEnterPhase(from) {
    if(phase == 2) {
        triggerSpawner(unit, Element.Mokshi_Spawner_CannonDefense);
    }
}

function onEnterSequence(k) {
    if(k == Sequences.EnterChrysalis) {
        forceSequence(Sequences.InChrysalis);
        forceCast(Skill.Mokshi_EnterChrysalis);
    }
}

function onSkillEnd(s, cancel) {
    if (s.kind == Skill.Mokshi_Phase2Screech) {
        forceSequence(Sequences.MoveToRoof);
        moveToElement(Element.Mokshi_ChrysalisPosition, true);
        requestSequence(Sequences.EnterChrysalis);
    }
}

function onStatusEnd(status, cancel) {
    if(inCombat && status.kind == Skill.Mokshi_ChrysalisStatus) {
        leaveSequence(Sequences.InChrysalis);
        goToPhase(3);
    }
}

function onCombatUpdate(dt) {
    var mokshi = toMokshi(unit);
    if(currentSequence == Sequences.InChrysalis) {
        mokshi.tryCastChrysalisLaser();
    }
    else if (phase == 3) {
        mokshi.tryCastEfflorescence(dt);
    }
}

function onCombatUpdate(dt) {
    var phrixes = toPhrixes(unit);
    if (phase == 2 || phase == 4) {
        phrixes.tryCastChaosOrb(dt);
    }
    if (phase == 3) {
        if(phrixes.heapsPhaseEnabled) {
            phrixes.tryCastChaosHeap(dt);
            var closestHero = getClosestHero();
            if(closestHero.withinRange(unit, vars.var1)) {
                phrixes.stopHeapsGeneration();
                trace("End chaos heaps");
            }
        }
    }
}

function onEnterCombat() {
    enableSpawner(unit, Element.Cleodora_Feeders, function(feeder, spawn) {
        feeder.target = unit;
        foeRequestSkill(feeder, Skill.CleodoraFeeder_Beam);
    });
    enableSpawner(unit, Element.Cleodora_Guards);
}

function onEnterPhase(from) {
    if(phase > 1) {
        disableSpawner(unit, Element.Cleodora_Feeders);
        disableSpawner(unit, Element.Cleodora_Guards);
    }
}

function onLeaveCombat() {
    disableSpawner(unit, Element.Cleodora_Feeders);
    disableSpawner(unit, Element.Cleodora_Guards);
}
